create table inventory_items (id bigint generated by default as identity primary key, make text, model text, serial_number text, year text, caliber text, purchase_price numeric, description text, condition text, created_at timestamptz default now()); create table app_settings (id int primary key, passcode_hash text); alter table inventory_items enable row level security; alter table app_settings enable row level security; create policy "all" on inventory_items for all using (true) with check (true); create policy "all2" on app_settings for all using (true) with check (true);